"// ─── Orbit Trail ─────────────────────────────────────────────────────────────
const OrbitTrail: React.FC<{ a: number; b: number; tilt: number; tiltZ: number }> = ({ a, b, tilt, tiltZ }) => {
  const lineObject = useMemo(() => {
    const pts: THREE.Vector3[] = [];
    const m = new THREE.Matrix4().makeRotationX(tilt).multiply(new THREE.Matrix4().makeRotationZ(tiltZ));
    for (let i = 0; i <= 128; i++) {
      const angle = (i / 128) * Math.PI * 2;
      const v = new THREE.Vector3(Math.cos(angle) * a, Math.sin(angle) * b, 0).applyMatrix4(m);
      pts.push(v);
    }
    const geo = new THREE.BufferGeometry().setFromPoints(pts);
    const mat = new THREE.LineBasicMaterial({
      color: '#334466',
      transparent: true,
      opacity: 0.18,
      blending: THREE.AdditiveBlending,
      depthWrite: false,
    });
    return new THREE.Line(geo, mat);
  }, [a, b, tilt, tiltZ]);

  return <primitive object={lineObject} />;
};
"

